const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';
const userFilter = userId ? '&user_id=eq.' + encodeURIComponent(userId) : '';
const operation = trigger.operation || 'list_drafts';
let contentId = trigger.content_id || '';
const contentTitle = trigger.content_title || '';
const triggerChapterNumber = trigger.chapter_number || '';
const triggerProjectTitle = trigger.project_title || '';
const typeFilter = trigger.content_type_filter || '';
const scheduleDate = trigger.schedule_date || '';

// Resolve "prologue"/"epilogue" to chapter_number before title lookup
const isPrologueRef = /\bprologue\b/i.test(contentTitle.trim()) && !/chapter\s*\d/i.test(contentTitle.trim());
const isEpilogueRef = /\bepilogue\b/i.test(contentTitle.trim()) && !/chapter\s*\d/i.test(contentTitle.trim());
let prologueEpilogueProjectFilter = '';
if (isPrologueRef || isEpilogueRef) {
  const projName = contentTitle.replace(/\b(the\s+)?(prologue|epilogue)\b/gi, '').replace(/[\s\-—]+/g, ' ').replace(/^\s*(of|from|for|in)\s+/i, '').trim();
  if (projName) {
    const projResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(projName) + '*&select=id&limit=1' + userFilter, headers });
    if (Array.isArray(projResp) && projResp.length > 0) {
      prologueEpilogueProjectFilter = '&project_id=eq.' + projResp[0].id;
    }
  }
}

// Title → ID resolution: if content_title is provided but content_id is not, look it up
if (!contentId && contentTitle && ['approve', 'publish', 'reject', 'delete', 'undelete', 'schedule', 'unschedule', 'unpublish', 'list_versions', 'get_version', 'save_version'].includes(operation)) {
  // Fetch all title matches, then filter by valid status in JS (PostgREST ignores status filter with ilike)
  let lookupUrl;
  if (isPrologueRef) {
    lookupUrl = supabaseUrl + '/rest/v1/published_content_v2?chapter_number=eq.0&content_type=eq.chapter&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter + prologueEpilogueProjectFilter;
  } else if (isEpilogueRef) {
    lookupUrl = supabaseUrl + '/rest/v1/published_content_v2?chapter_number=eq.999&content_type=eq.chapter&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter + prologueEpilogueProjectFilter;
  } else {
    // Check if this is a "Chapter N" or "Project - Chapter N" reference
    const chapterMatch = contentTitle.match(/chapter\s*(\d+)/i);
    if (chapterMatch) {
      const chNum = parseInt(chapterMatch[1]);
      const chProjName = contentTitle.replace(/[-—]?\s*chapter\s*\d+/i, '').replace(/^[\s\-—]+|[\s\-—]+$/g, '').trim();
      let chProjectFilter = '';
      if (chProjName) {
        const chProjResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(chProjName) + '*&select=id&limit=1' + userFilter, headers });
        if (Array.isArray(chProjResp) && chProjResp.length > 0) {
          chProjectFilter = '&project_id=eq.' + chProjResp[0].id;
        }
      }
      lookupUrl = supabaseUrl + '/rest/v1/published_content_v2?chapter_number=eq.' + chNum + '&content_type=eq.chapter&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter + chProjectFilter;
    } else {
      lookupUrl = supabaseUrl + '/rest/v1/published_content_v2?title=ilike.' + encodeURIComponent(contentTitle) + '&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter;
    }
  }
  if (typeFilter) lookupUrl += '&content_type=eq.' + typeFilter;
  const allMatches = await this.helpers.httpRequest({ method: 'GET', url: lookupUrl, headers });
  const validStatuses = operation === 'approve' ? ['draft']
    : operation === 'publish' ? ['approved']
    : operation === 'reject' ? ['draft', 'approved']
    : operation === 'schedule' ? ['draft', 'approved']
    : operation === 'unschedule' ? ['scheduled']
    : operation === 'unpublish' ? ['published']
    : operation === 'delete' ? ['draft', 'approved', 'rejected', 'scheduled']
    : operation === 'undelete' ? ['deleted']
    : null;
  let matches = validStatuses
    ? (Array.isArray(allMatches) ? allMatches.filter(m => validStatuses.includes(m.status)) : [])
    : (Array.isArray(allMatches) ? allMatches : []);
  // Fallback 1: use explicit chapter_number + project_title if provided
  if ((!Array.isArray(matches) || matches.length === 0) && triggerChapterNumber) {
    let fbChNum = null;
    if (/^(prologue|prol|0)$/i.test(triggerChapterNumber)) fbChNum = 0;
    else if (/^(epilogue|epil)$/i.test(triggerChapterNumber)) fbChNum = 999;
    else if (/^\d+$/.test(triggerChapterNumber)) fbChNum = parseInt(triggerChapterNumber);
    if (fbChNum !== null) {
      let fbProjFilter2 = '';
      if (triggerProjectTitle) {
        const fp2 = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(triggerProjectTitle) + '*&select=id&limit=1' + userFilter, headers });
        if (Array.isArray(fp2) && fp2.length > 0) fbProjFilter2 = '&project_id=eq.' + fp2[0].id;
      }
      const fb2Resp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?chapter_number=eq.' + fbChNum + '&content_type=eq.chapter&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter + fbProjFilter2, headers });
      if (Array.isArray(fb2Resp) && fb2Resp.length > 0) {
        matches = validStatuses ? fb2Resp.filter(m => validStatuses.includes(m.status)) : fb2Resp;
      }
    }
  }
  // Fallback 2: if title lookup failed and contentTitle looks like it could be a chapter reference, try chapter_number
  if ((!Array.isArray(matches) || matches.length === 0) && !isPrologueRef && !isEpilogueRef) {
    const fallbackChMatch = contentTitle.match(/chapter\s*(\d+)/i);
    const fallbackProl = /\bprologue\b/i.test(contentTitle);
    const fallbackEpil = /\bepilogue\b/i.test(contentTitle);
    const fallbackChNum = fallbackChMatch ? parseInt(fallbackChMatch[1]) : (fallbackProl ? 0 : (fallbackEpil ? 999 : null));
    if (fallbackChNum !== null) {
      const fbProjName = contentTitle.replace(/[-—]?\s*(chapter\s*\d+|prologue|epilogue)/i, '').replace(/^[\s\-—]+|[\s\-—]+$/g, '').replace(/^\s*(of|from|for|in|the)\s+/i, '').trim();
      let fbProjFilter = '';
      if (fbProjName) {
        const fbProjResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(fbProjName) + '*&select=id&limit=1' + userFilter, headers });
        if (Array.isArray(fbProjResp) && fbProjResp.length > 0) fbProjFilter = '&project_id=eq.' + fbProjResp[0].id;
      }
      const fbResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?chapter_number=eq.' + fallbackChNum + '&content_type=eq.chapter&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at' + userFilter + fbProjFilter, headers });
      if (Array.isArray(fbResp) && fbResp.length > 0) {
        matches = validStatuses ? fbResp.filter(m => validStatuses.includes(m.status)) : fbResp;
      }
    }
  }
  if (!Array.isArray(matches) || matches.length === 0) {
    const statusMsg = operation === 'approve' ? 'only drafts can be approved'
      : operation === 'publish' ? 'only approved items can be published — use approve first'
      : operation === 'reject' ? 'only draft or approved items can be rejected'
      : operation === 'schedule' ? 'only draft or approved items can be scheduled'
      : operation === 'unschedule' ? 'only scheduled items can be unscheduled'
      : operation === 'unpublish' ? 'only published items can be unpublished'
      : operation === 'delete' ? 'published items must be unpublished first before deleting'
      : operation === 'undelete' ? 'only deleted items can be undeleted'
      : '';
    return [{ json: { result: 'FAILED — NOTHING WAS APPROVED/CHANGED. No eligible content found with title "' + contentTitle + '"' + (statusMsg ? ' (' + statusMsg + ')' : '') + '. Use list_drafts or list_approved to see available items.', send_notification: false } }];
  } else if (matches.length > 1) {
    const uniqueTypes = [...new Set(matches.map(m => m.content_type))];
    const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const lines = matches.map((m, i) => letters[i] + '. ' + m.title + ' — ' + m.content_type + ' — ' + new Date(m.created_at || 0).toLocaleDateString() + ' — ' + m.status + ' [ID:' + m.id + ']');
    const display = lines.join('\n');
    return [{ json: { result: 'NEEDS_CLARIFICATION — say this to the user word for word:\nI found ' + matches.length + ' items with that title. Which one?\n' + display + '\nReply A, B, C etc. (agent: once user picks, call manage_library again with content_id from the matching [ID:...] above)', send_notification: false } }];
  } else {
    contentId = matches[0].id;
  }
}
let recipientEmail = trigger.recipient_email;
let bccEmail = trigger.bcc_email;
if (!recipientEmail) {
  try {
    const emailRows = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value' + userFilter,
      headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }
    });
    for (const row of emailRows) {
      if (row.key === 'recipient_email') recipientEmail = row.value;
      if (row.key === 'bcc_email') bccEmail = row.value;
    }
  } catch (e) {
    recipientEmail = 'eric@agileadtesting.com';
    bccEmail = '';
  }
}
recipientEmail = recipientEmail || 'eric@agileadtesting.com';
bccEmail = bccEmail || '';

let result = '';
let send_notification = false;
let notification_subject = '';
let notification_body = '';
let content_title = '';

// Helper: save a version snapshot to content_versions
async function saveVersionSnapshot(cId, changedBy, changeNote) {
  // GET current content_text and title
  const contentResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + cId + '&select=content_text,title' + userFilter,
    headers
  });
  const contentRow = Array.isArray(contentResp) && contentResp.length > 0 ? contentResp[0] : null;
  if (!contentRow) return null;

  // GET max version_number
  const versionsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/content_versions_v2?content_id=eq.' + cId + '&order=version_number.desc&limit=1&select=version_number' + userFilter,
    headers
  });
  const maxVersion = Array.isArray(versionsResp) && versionsResp.length > 0 ? versionsResp[0].version_number : 0;
  const newVersion = maxVersion + 1;

  // POST new version
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/content_versions_v2',
    headers: { ...headers, 'Prefer': 'return=minimal' },
    body: {
      content_id: cId,
      version_number: newVersion,
      content_text: contentRow.content_text || '',
      changed_by: changedBy,
      change_note: changeNote,
      created_at: new Date().toISOString(),
      ...(userId ? { user_id: userId } : {})
    }
  });
  return { version_number: newVersion, title: contentRow.title };
}

// Helper: build notification HTML
function buildNotification(op, title, newStatus) {
  const now = new Date().toISOString();
  notification_subject = 'Content Library: ' + op.charAt(0).toUpperCase() + op.slice(1) + ' - ' + (title || 'Untitled');
  notification_body = '<h2>Content Library Update</h2>' +
    '<p><strong>Action:</strong> ' + op + '</p>' +
    '<p><strong>Title:</strong> ' + (title || 'Untitled') + '</p>' +
    '<p><strong>New Status:</strong> ' + newStatus + '</p>' +
    '<p><strong>Time:</strong> ' + now + '</p>';
  send_notification = true;
}

if (operation === 'email_content') {
  // Email any content type: outline, research, chapter, short_story, blog_post, newsletter
  const emailType = typeFilter || 'outline';
  const searchTitle = contentTitle || '';
  if (!searchTitle) {
    result = 'Error: content_title is required for email_content. Specify the title of the content to email.';
  } else {
    let fetchedTitle = '';
    let fetchedContent = '';
    let fetchedGenre = '';
    // Helper: basic markdown to HTML
    function md2html(md) {
      let h = md.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
      h = h.replace(/^### (.+)$/gm, '<h3>$1</h3>');
      h = h.replace(/^## (.+)$/gm, '<h2>$1</h2>');
      h = h.replace(/^# (.+)$/gm, '<h1>$1</h1>');
      h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
      h = h.replace(/\*(.+?)\*/g, '<em>$1</em>');
      h = h.replace(/^[-*] (.+)$/gm, '<li>$1</li>');
      h = h.replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>');
      h = h.replace(/<\/ul>\s*<ul>/g, '');
      h = h.replace(/\n\n/g, '</p><p>');
      h = '<p>' + h + '</p>';
      h = h.replace(/<p><h([123])>/g, '<h$1>').replace(/<\/h([123])><\/p>/g, '</h$1>');
      h = h.replace(/<p><ul>/g, '<ul>').replace(/<\/ul><\/p>/g, '</ul>');
      return h;
    }
    // Helper: format outline JSON to HTML
    function outlineToHtml(outline) {
      if (!outline || typeof outline !== 'object') return '<p>No outline data.</p>';
      let html = '<h1>' + (outline.title || 'Untitled') + '</h1>';
      if (outline.premise) html += '<p><strong>Premise:</strong> ' + outline.premise + '</p>';
      if (outline.themes && Array.isArray(outline.themes)) html += '<p><strong>Themes:</strong> ' + outline.themes.join(', ') + '</p>';
      if (outline.characters && Array.isArray(outline.characters)) {
        html += '<h2>Characters</h2><ul>';
        for (const c of outline.characters) {
          html += '<li><strong>' + (c.name || 'Unknown') + '</strong> (' + (c.role || '') + ') — ' + (c.description || '') + (c.arc ? '<br/><em>Arc: ' + c.arc + '</em>' : '') + '</li>';
        }
        html += '</ul>';
      }
      if (outline.chapters && Array.isArray(outline.chapters)) {
        html += '<h2>Chapters</h2>';
        for (const ch of outline.chapters) {
          const num = ch.number === 0 ? 'Prologue' : ch.number === 999 ? 'Epilogue' : 'Chapter ' + ch.number;
          html += '<h3>' + num + ': ' + (ch.title || 'Untitled') + '</h3>';
          if (ch.brief) html += '<p>' + ch.brief + '</p>';
          if (ch.arc_notes) html += '<p><em>Arc notes: ' + ch.arc_notes + '</em></p>';
          if (ch.research_topics && Array.isArray(ch.research_topics) && ch.research_topics.length > 0) html += '<p><em>Research: ' + ch.research_topics.join(', ') + '</em></p>';
        }
      }
      return html;
    }
    try {
      if (emailType === 'outline') {
        const resp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(searchTitle) + '&select=title,genre_slug,outline&outline=not.is.null&limit=1' + userFilter, headers });
        if (Array.isArray(resp) && resp.length > 0 && resp[0].outline && Object.keys(resp[0].outline).length > 0) {
          fetchedTitle = resp[0].title;
          fetchedGenre = resp[0].genre_slug || '';
          fetchedContent = outlineToHtml(resp[0].outline);
        } else {
          result = 'Error: No outline found for "' + searchTitle + '".';
        }
      } else if (emailType === 'research') {
        const resp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/research_reports_v2?topic=ilike.' + encodeURIComponent('%' + searchTitle + '%') + '&select=topic,genre_slug,content&order=created_at.desc&limit=1' + userFilter, headers });
        if (Array.isArray(resp) && resp.length > 0 && resp[0].content) {
          fetchedTitle = resp[0].topic;
          fetchedGenre = resp[0].genre_slug || '';
          fetchedContent = md2html(resp[0].content);
        } else {
          result = 'Error: No research report found matching "' + searchTitle + '".';
        }
      } else {
        // chapter, short_story, blog_post, newsletter — from published_content_v2
        let url = supabaseUrl + '/rest/v1/published_content_v2?title=ilike.' + encodeURIComponent(searchTitle) + '&select=title,genre_slug,content_text,content_type&order=created_at.desc&limit=1' + userFilter;
        if (emailType && emailType !== 'any') url += '&content_type=eq.' + emailType;
        const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
        if (Array.isArray(resp) && resp.length > 0 && resp[0].content_text) {
          fetchedTitle = resp[0].title;
          fetchedGenre = resp[0].genre_slug || '';
          fetchedContent = md2html(resp[0].content_text);
        } else {
          result = 'Error: No ' + emailType + ' found matching "' + searchTitle + '".';
        }
      }
      if (fetchedContent && !result) {
        const genreLabel = fetchedGenre ? ' (' + fetchedGenre + ')' : '';
        notification_subject = fetchedTitle + genreLabel;
        notification_body = '<div style="font-family: Georgia, serif; max-width: 800px; margin: 0 auto; padding: 20px;">' + fetchedContent + '</div>';
        send_notification = true;
        result = 'Email sent: "' + fetchedTitle + '" (' + emailType + ') has been emailed to you.';
      }
    } catch (e) {
      result = 'Error fetching content: ' + (e.message || String(e));
    }
  }

} else if (operation === 'list_all') {
  let url = supabaseUrl + '/rest/v1/published_content_v2?status=neq.deleted&order=created_at.desc&limit=50&select=id,title,content_type,genre_slug,status,created_at,published_at' + userFilter;
  if (typeFilter) url += '&content_type=eq.' + typeFilter;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No content found in library.';
  } else {
    result = 'Found ' + items.length + ' item(s) total:\n' + items.map((item, i) =>
      (i + 1) + '. [' + item.status.toUpperCase() + '] ' + item.title + ' (' + item.content_type + ', ' + (item.genre_slug || 'no genre') + ') \u2014 ' + new Date(item.created_at).toLocaleDateString() + ' [ID: ' + item.id + ']'
    ).join('\n');
  }

} else if (operation === 'list_drafts' || operation === 'list_published' || operation === 'list_approved' || operation === 'list_rejected' || operation === 'list_deleted') {
  const status = operation === 'list_drafts' ? 'draft' : operation === 'list_approved' ? 'approved' : operation === 'list_rejected' ? 'rejected' : operation === 'list_deleted' ? 'deleted' : 'published';
  let url = supabaseUrl + '/rest/v1/published_content_v2?status=eq.' + status + '&order=created_at.desc&limit=20&select=id,title,content_type,genre_slug,status,created_at,published_at' + userFilter;
  if (typeFilter) url += '&content_type=eq.' + typeFilter;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No ' + status + ' content found.';
  } else {
    result = 'Found ' + items.length + ' ' + status + ' item(s):\n' + items.map((item, i) => 
      (i + 1) + '. ' + item.title + ' (' + item.content_type + ', ' + (item.genre_slug || 'no genre') + ') \u2014 ' + new Date(item.created_at).toLocaleDateString() + ' [ID: ' + item.id + ']'
    ).join('\n');
  }

} else if (operation === 'list_scheduled') {
  let url = supabaseUrl + '/rest/v1/published_content_v2?status=eq.scheduled&order=created_at.desc&limit=20&select=id,title,content_type,genre_slug,status,metadata,created_at' + userFilter;
  if (typeFilter) url += '&content_type=eq.' + typeFilter;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No scheduled content found.';
  } else {
    result = 'Found ' + items.length + ' scheduled item(s):\n' + items.map((item, i) => {
      const sd = item.metadata && item.metadata.schedule_date ? item.metadata.schedule_date : 'no date';
      return (i + 1) + '. ' + item.title + ' (' + item.content_type + ', ' + (item.genre_slug || 'no genre') + ') \u2014 Scheduled: ' + sd + ' [ID: ' + item.id + ']';
    }).join('\n');
  }

} else if (operation === 'list_versions') {
  if (!contentId) {
    result = 'Error: content_id is required for list_versions operation.';
  } else {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/content_versions_v2?content_id=eq.' + contentId + '&order=version_number.desc&select=version_number,changed_by,change_note,created_at' + userFilter,
      headers
    });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length === 0) {
      result = 'No versions found for content_id: ' + contentId;
    } else {
      result = 'Found ' + items.length + ' version(s):\n' + items.map((v, i) =>
        'v' + v.version_number + ' \u2014 ' + (v.changed_by || 'unknown') + ' \u2014 ' + (v.change_note || 'no note') + ' \u2014 ' + new Date(v.created_at).toLocaleDateString()
      ).join('\n');
    }
  }

} else if (operation === 'get_version') {
  const versionNumber = trigger.version_number;
  if (!contentId || !versionNumber) {
    result = 'Error: content_id and version_number are required for get_version operation.';
  } else {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/content_versions_v2?content_id=eq.' + contentId + '&version_number=eq.' + versionNumber + '&select=version_number,content_text,changed_by,change_note,created_at' + userFilter,
      headers
    });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length === 0) {
      result = 'Version ' + versionNumber + ' not found for content_id: ' + contentId;
    } else {
      const v = items[0];
      result = 'Version ' + v.version_number + ' by ' + (v.changed_by || 'unknown') + ':\n' + (v.content_text || '(empty)');
    }
  }

} else if (operation === 'save_version') {
  if (!contentId) {
    result = 'Error: content_id is required for save_version operation.';
  } else {
    const changedBy = trigger.changed_by || 'system';
    const changeNote = trigger.change_note || 'Manual version snapshot';
    const snapshot = await saveVersionSnapshot.call(this, contentId, changedBy, changeNote);
    if (!snapshot) {
      result = 'Error: content not found for content_id: ' + contentId;
    } else {
      result = 'Version ' + snapshot.version_number + ' saved for "' + snapshot.title + '".';
    }
  }

} else if (operation === 'schedule') {
  if (!contentId || !scheduleDate) {
    result = 'Error: content_id and schedule_date are required for schedule operation.';
  } else {
    // GET existing metadata to merge
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=metadata,title' + userFilter,
      headers
    });
    const row = Array.isArray(existing) && existing.length > 0 ? existing[0] : null;
    if (!row) {
      result = 'Error: content not found for content_id: ' + contentId;
    } else {
      content_title = row.title || 'Untitled';
      const existingMeta = row.metadata && typeof row.metadata === 'object' ? row.metadata : {};
      const mergedMeta = { ...existingMeta, schedule_date: scheduleDate };
      const body = { status: 'scheduled', metadata: mergedMeta, updated_at: new Date().toISOString() };
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter,
        headers: { ...headers, 'Prefer': 'return=representation' },
        body
      });
      result = 'Content "' + content_title + '" scheduled for ' + scheduleDate + '. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';
      buildNotification('schedule', content_title, 'scheduled');
    }
  }

} else if (operation === 'unschedule') {
  if (!contentId) {
    result = 'Error: content_id required for unschedule.';
  } else {
    const existing = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=title,metadata' + userFilter, headers });
    const row = Array.isArray(existing) && existing.length > 0 ? existing[0] : null;
    if (!row) { result = 'Error: content not found.'; } else {
      content_title = row.title || 'Untitled';
      const meta = row.metadata && typeof row.metadata === 'object' ? { ...row.metadata } : {};
      delete meta.schedule_date;
      await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter, headers: { ...headers, 'Prefer': 'return=representation' }, body: { status: 'draft', metadata: meta, updated_at: new Date().toISOString() } });
      result = 'Content "' + content_title + '" unscheduled \u2014 status reverted to draft. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';
      buildNotification('unschedule', content_title, 'draft');
    }
  }

} else if (operation === 'unpublish') {
  if (!contentId) {
    result = 'Error: content_id is required for unpublish operation.';
  } else {
    const titleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=title' + userFilter,
      headers
    });
    content_title = Array.isArray(titleResp) && titleResp.length > 0 ? (titleResp[0].title || 'Untitled') : 'Untitled';
    const body = { status: 'approved', published_at: null, updated_at: new Date().toISOString() };
    await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter, headers: { ...headers, 'Prefer': 'return=representation' }, body });
    result = 'Content "' + content_title + '" unpublished \u2014 status reverted to approved. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';
    buildNotification('unpublish', content_title, 'approved');
  }

} else if (operation === 'delete') {
  if (!contentId) {
    result = 'Error: content_id is required for delete operation.';
  } else {
    const changeNote = 'Auto-snapshot before delete';
    await saveVersionSnapshot.call(this, contentId, 'system', changeNote);
    const titleResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=title' + userFilter, headers });
    content_title = Array.isArray(titleResp) && titleResp.length > 0 ? (titleResp[0].title || 'Untitled') : 'Untitled';
    const body = { status: 'deleted', updated_at: new Date().toISOString() };
    await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter, headers: { ...headers, 'Prefer': 'return=representation' }, body });
    result = 'Content "' + content_title + '" moved to trash (soft-deleted). Use undelete to restore it. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';
    buildNotification('delete', content_title, 'deleted');
  }

} else if (operation === 'undelete') {
  if (!contentId) {
    result = 'Error: content_id is required for undelete operation.';
  } else {
    const titleResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=title' + userFilter, headers });
    content_title = Array.isArray(titleResp) && titleResp.length > 0 ? (titleResp[0].title || 'Untitled') : 'Untitled';
    const body = { status: 'draft', updated_at: new Date().toISOString() };
    await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter, headers: { ...headers, 'Prefer': 'return=representation' }, body });
    result = 'Content "' + content_title + '" restored from trash — status reverted to draft. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';
    buildNotification('undelete', content_title, 'draft');
  }

} else if (operation === 'approve_all_chapters' || operation === 'publish_all_chapters') {
  const bulkOp = operation.startsWith('approve') ? 'approved' : 'published';
  const bulkFromStatus = operation.startsWith('approve') ? 'draft' : 'approved';
  let bulkProjFilter = '';
  const bulkProjectName = contentTitle || triggerProjectTitle || '';
  if (bulkProjectName) {
    const bpResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(bulkProjectName) + '*&select=id,title&limit=1' + userFilter, headers });
    if (Array.isArray(bpResp) && bpResp.length > 0) bulkProjFilter = '&project_id=eq.' + bpResp[0].id;
  }
  const bulkResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/published_content_v2?content_type=eq.chapter&status=eq.' + bulkFromStatus + '&order=chapter_number.asc&select=id,title,chapter_number' + userFilter + bulkProjFilter, headers });
  const bulkChapters = Array.isArray(bulkResp) ? bulkResp : [];
  if (bulkChapters.length === 0) {
    result = 'FAILED — No ' + bulkFromStatus + ' chapters found' + (triggerProjectTitle ? ' for "' + triggerProjectTitle + '"' : '') + '.';
  } else {
    for (const ch of bulkChapters) {
      await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + ch.id + userFilter, headers, body: { status: bulkOp, updated_at: new Date().toISOString() } });
    }
    const labels = bulkChapters.map(ch => ch.chapter_number === 0 ? 'Prologue' : (ch.chapter_number === 999 ? 'Epilogue' : 'Chapter ' + ch.chapter_number) + ': ' + ch.title);
    result = 'Successfully ' + bulkOp + ' ' + bulkChapters.length + ' chapters:\n' + labels.join('\n');
    buildNotification(operation.startsWith('approve') ? 'approve' : 'publish', bulkChapters.length + ' chapters', bulkOp);
  }
} else if (['approve', 'publish', 'reject'].includes(operation)) {
  if (!contentId) {
    result = 'Error: content_id is required for ' + operation + ' operation.';
  } else {
    // Auto-snapshot version before approve/publish
    if (operation === 'approve' || operation === 'publish') {
      const changeNote = 'Auto-snapshot before ' + operation;
      await saveVersionSnapshot.call(this, contentId, 'system', changeNote);
    }

    // Get title for notification
    const titleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + '&select=title' + userFilter,
      headers
    });
    content_title = Array.isArray(titleResp) && titleResp.length > 0 ? (titleResp[0].title || 'Untitled') : 'Untitled';

    const newStatus = operation === 'approve' ? 'approved' : operation === 'publish' ? 'published' : 'rejected';
    const body = { status: newStatus, updated_at: new Date().toISOString() };
    if (operation === 'publish') body.published_at = new Date().toISOString();
    await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content_v2?id=eq.' + contentId + userFilter, headers: { ...headers, 'Prefer': 'return=representation' }, body });
    result = 'Content "' + content_title + '" ' + (operation === 'approve' ? 'approved' : operation === 'publish' ? 'published' : 'rejected') + ' successfully. [ID: ' + contentId + '] (agent: use this content_id for the next operation on this item)';

    buildNotification(operation, content_title, newStatus);
  }

} else if (operation === 'list_projects') {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?order=created_at.desc&select=id,title,genre_slug,created_at' + userFilter,
    headers
  });
  const projects = Array.isArray(resp) ? resp : [];
  if (projects.length === 0) {
    result = 'No writing projects found. Start by brainstorming a story.';
  } else {
    result = 'Found ' + projects.length + ' writing project(s):\n' + projects.map((p, i) =>
      (i + 1) + '. ' + p.title + ' (' + (p.genre_slug || 'no genre') + ') \u2014 created ' + new Date(p.created_at).toLocaleDateString()
    ).join('\n');
  }

} else {
  result = 'Unknown operation: ' + operation + '. Valid operations: list_all, list_drafts, list_approved, list_published, list_rejected, list_scheduled, list_deleted, list_versions, get_version, save_version, schedule, unschedule, approve, publish, reject, unpublish, delete, undelete, email_content, list_projects';
}

return [{ json: { result, send_notification, notification_subject, notification_body, recipient_email: recipientEmail, bcc_email: bccEmail } }];
